mapper.sql:
from aiw_ai_prompt_evaluation e
where 1 = 1

    and (
        e.evaluator_biz_id = #{criteria.visibleUserBizId}
        or exists (
            select 1
            from aiw_investment_feedback f
            where f.biz_id = e.feedback_biz_id
              and f.user_biz_id = #{criteria.visibleUserBizId}
        )
        or exists (
            select 1
            from aiw_backtest_result b
            where b.biz_id = e.backtest_biz_id
              and b.owner_user_biz_id = #{criteria.visibleUserBizId}
        )
    )


    and e.prompt_code = #{criteria.promptCode}


    and e.prompt_version = #{criteria.promptVersion}


    and e.scenario = #{criteria.scenario}


    and e.backtest_biz_id = #{criteria.backtestBizId}


    and e.feedback_biz_id = #{criteria.feedbackBizId}


    and e.review_status = #{criteria.reviewStatus}

mapper.select:
select e.* 
order by ${sortColumn}

    asc
    desc

limit #{offset}, #{criteria.size}
